// Represents raw data coming into the pipeline
struct RawDataPoint {
    double x;
    double y;
    double z;
    int category;
    std::string label;
};

// Intermediate normalized representation
struct NormalizedData {
    double nx;
    double ny;
    double nz;
    double magnitude;
    int category;
    std::string label;

    NormalizedData(const RawDataPoint& raw) {
        magnitude = std::sqrt(raw.x * raw.x + raw.y * raw.y + raw.z * raw.z);
        if (magnitude > 0.0) {
            nx = raw.x / magnitude;
            ny = raw.y / magnitude;
            nz = raw.z / magnitude;
        } else {
            nx = ny = nz = 0.0;
        }
        category = raw.category;
        label = raw.label;
    }
};

// Intermediate filtered representation
struct FilteredData {
    double nx;
    double ny;
    double nz;
    double magnitude;
    double weight;
    std::string label;

    FilteredData(const NormalizedData& norm, double w)
        : nx(norm.nx), ny(norm.ny), nz(norm.nz),
          magnitude(norm.magnitude), weight(w), label(norm.label) {}
};

// Final transformed output
struct TransformedResult {
    double score;
    double weighted_magnitude;
    std::string label;
};

