// GOOD VERSION: Avoids unnecessary heap allocations, reuses buffers,
// minimizes copies, reserves vector capacity upfront.
class DataTransformer {
public:
    // Pre-allocated intermediate buffers
    void reserve(size_t capacity) {
        normalized_buffer_.reserve(capacity);
        filtered_buffer_.reserve(capacity);
        results_buffer_.reserve(capacity);
    }

    const std::vector<TransformedResult>& transform_data(const std::vector<RawDataPoint>& input) {
        const size_t n = input.size();

        // Reuse pre-allocated buffers instead of allocating each time
        normalized_buffer_.clear();
        filtered_buffer_.clear();
        results_buffer_.clear();

        // Ensure capacity without repeated reallocation
        if (normalized_buffer_.capacity() < n) {
            normalized_buffer_.reserve(n);
            filtered_buffer_.reserve(n);
            results_buffer_.reserve(n);
        }

        // Step 1: Normalize all — stack-like temporaries stored in contiguous buffer
        for (const auto& raw : input) {
            normalized_buffer_.emplace_back(raw);
        }

        // Step 2: Filter — use move semantics for strings to avoid copies
        for (auto& norm : normalized_buffer_) {
            double weight = 1.0 / (1.0 + std::exp(-norm.magnitude));
            filtered_buffer_.emplace_back(norm, weight);
        }

        // Release normalized buffer memory contents early (strings)
        normalized_buffer_.clear();

        // Step 3: Produce final results — move strings from filtered data
        for (auto& filt : filtered_buffer_) {
            TransformedResult result;
            result.score = filt.nx * filt.weight +
                           filt.ny * filt.weight +
                           filt.nz * filt.weight;
            result.weighted_magnitude = filt.magnitude * filt.weight;
            result.label = std::move(filt.label); // move instead of copy
            results_buffer_.push_back(std::move(result));
        }

        filtered_buffer_.clear();

        return results_buffer_;
    }

private:
    std::vector<NormalizedData> normalized_buffer_;
    std::vector<FilteredData> filtered_buffer_;
    std::vector<TransformedResult> results_buffer_;
};

// Even more optimized: single-pass, no intermediate buffers at all
class DataTransformerFused {
public:
    void reserve(size_t capacity) {
        results_buffer_.reserve(capacity);
    }

    const std::vector<TransformedResult>& transform_data(const std::vector<RawDataPoint>& input) {
        const size_t n = input.size();
        results_buffer_.clear();
        if (results_buffer_.capacity() < n) {
            results_buffer_.reserve(n);
        }

        for (const auto& raw : input) {
            // All intermediates on the stack — no heap allocation
            double magnitude = std::sqrt(raw.x * raw.x + raw.y * raw.y + raw.z * raw.z);
            double inv_mag = (magnitude > 0.0) ? (1.0 / magnitude) : 0.0;
            double nx = raw.x * inv_mag;
            double ny = raw.y * inv_mag;
            double nz = raw.z * inv_mag;
            double weight = 1.0 / (1.0 + std::exp(-magnitude));

            TransformedResult result;
            result.score = (nx + ny + nz) * weight;
            result.weighted_magnitude = magnitude * weight;
            result.label = raw.label; // single copy (unavoidable if we need our own copy)
            results_buffer_.push_back(std::move(result));
        }

        return results_buffer_;
    }

private:
    std::vector<TransformedResult> results_buffer_;
};

